  ('dietitian-moex-00353', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '臺灣冬天盛產之蔬菜有那些？①綠竹筍　②苦瓜　③茼蒿　④白蘿蔔', '["①②", "①③", "①④", "③④"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "60192659f8f1", "answer_pdf_sha1": "07e12825c8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "22", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00354', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依據食品良好衛生規範準則，下列何者不是學校餐廳餐飲作業場所應符合之規定？', '["洗滌場所應有充足之流動自來水及具有洗滌沖洗及有效殺菌功能之餐具洗滌殺菌設施", "其販賣櫃台無須與調理、製作及操作場所有效區隔", "廚房依據作業廠所配置截油設施應保持乾淨", "廚房應有維持室溫及油煙處理之措施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "60192659f8f1", "answer_pdf_sha1": "07e12825c8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "22", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00355', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '何謂採購量（As Purchased, AP）？', '["指供應商所提供的重量", "指食材可食部分的重量", "指食材經前處理後所剩的重量", "指食材在市場上的原始販售重量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "60192659f8f1", "answer_pdf_sha1": "07e12825c8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "22", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00356', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '關於食材或物品「比價採購」的做法，下列敘述何者正確？', '["不須公告，可個別告知合格廠商進行競價，報價最低者得標", "物品需要量多，但供應來源分散各地，可訂定價格，定期收購", "請求廠商提供報價單、產品目錄或樣品，再發出訂購單，進行買賣", "公告所需物品規格，使有供應能力的廠商按規定投報價格，當眾開標"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "60192659f8f1", "answer_pdf_sha1": "07e12825c8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "22", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00357', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '蔬果類食材採購原則，下列敘述何者錯誤？', '["柳橙選擇果色橙黃，果皮油胞細緻", "番茄選擇顏色鮮艷，有光澤無裂痕", "綠色甜椒選擇光澤鮮明，肉質厚者", "花胡瓜瓜身挺直，有瓜刺突起明顯者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "60192659f8f1", "answer_pdf_sha1": "07e12825c8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "22", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00358', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有關保溫餐車之敘述，下列何者正確？', '["加熱型保溫餐車加熱後溫度可達90℃", "加熱型保溫餐車中的餐食中心溫度宜達60℃", "冷存型保溫餐車的冷卻保溫溫度宜為15℃", "冷存型保溫餐車的餐食中心溫度宜達15℃"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "60192659f8f1", "answer_pdf_sha1": "07e12825c8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "22", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
